import * as fromTheme from '../actions/theme.actions';

export interface ThemeState {
    darkTheme: boolean;
    menuOpen: boolean;
}

export const initialState: ThemeState = {
    darkTheme: false,
    menuOpen: false,
};

export function themeReducer(
    state = initialState,
    action: fromTheme.ThemeActions
): ThemeState {
    switch (action.type) {
        case fromTheme.TOGGLE_DARK_MODE: {
            return {
                ...state,
                darkTheme: !state.darkTheme,
            };
        }

        case fromTheme.OPEN_CLOSE_MENU: {
            return {
                ...state,
                menuOpen: action.open,
            };
        }
    }
    return state;
}

export const getDarkTheme = (state: ThemeState) => state.darkTheme;
export const getMenuOpen = (state: ThemeState) => state.menuOpen;
